/* ── hook reveal ── */
function useReveal() {
  const ref = useRef(null);
  const [v, sv] = useState(false);
  useEffect(() => {
    const o = new IntersectionObserver(([e]) => { if (e.isIntersecting) { sv(true); o.disconnect(); } }, { threshold: 0.1 });
    if (ref.current) o.observe(ref.current);
    return () => o.disconnect();
  }, []);
  return [ref, v];
}
function Fade({ children, d = 0 }) {
  const [r, v] = useReveal();
  return <div ref={r} style={{ opacity: v?1:0, transform: v?"none":"translateY(20px)", transition: `opacity .6s ${d}ms, transform .6s ${d}ms` }}>{children}</div>;
}

