/* ── Cloudinary Video Player (JS SDK via CDN) ── */
const VIDS = [
  { src: "https://res.cloudinary.com/duvujaokq/video/upload/q_auto/f_auto/v1780120640/VID-20250902-WA0064_2_jbudah.mp4", label: "Session 01" },
  { src: "https://res.cloudinary.com/duvujaokq/video/upload/q_auto/f_auto/v1780120656/VID-20251029-WA0056_1_kyfxjt.mp4", label: "Session 02" },
  { src: "https://res.cloudinary.com/duvujaokq/video/upload/q_auto/f_auto/v1780120628/VID-20260327-WA0043_1_wl0tgh.mp4", label: "Session 03" },
];

function VidTile({ index = 0, label, h = 260 }) {
  const vid = VIDS[index] || VIDS[0];
  const lbl = label || vid.label;
  const [playing, setPlaying] = useState(false);
  const [errored, setErrored] = useState(false);
  const vidRef = useRef(null);

  const handlePlay = () => {
    if (vidRef.current) {
      vidRef.current.play().catch(() => setErrored(true));
      setPlaying(true);
    }
  };

  return (
    <div style={{ position:"relative", borderRadius:7, overflow:"hidden", border:"1px solid #1f2330", background:"#0a0b0e", height:h }}>
      <video
        ref={vidRef}
        src={vid.src}
        controls
        playsInline
        preload="none"
        crossOrigin="anonymous"
        onError={() => setErrored(true)}
        onPlay={() => setPlaying(true)}
        style={{ width:"100%", height:"100%", objectFit:"cover", display:"block" }}
      />
      {/* Overlay play button before user clicks */}
      {!playing && !errored && (
        <div
          onClick={handlePlay}
          style={{ position:"absolute", inset:0, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:10, cursor:"pointer", background:"rgba(0,0,0,.45)" }}>
          <div style={{ width:56, height:56, borderRadius:"50%", background:"rgba(201,168,76,.15)", border:"2px solid #c9a84c", display:"flex", alignItems:"center", justifyContent:"center", transition:"transform .2s" }}
            onMouseEnter={e => e.currentTarget.style.transform="scale(1.1)"}
            onMouseLeave={e => e.currentTarget.style.transform="scale(1)"}>
            <svg viewBox="0 0 24 24" width="24" height="24" fill="#c9a84c"><path d="M8 5v14l11-7z"/></svg>
          </div>
          <span style={{ color:"#c9a84c", fontSize:10, fontWeight:700, letterSpacing:".22em", textTransform:"uppercase" }}>{lbl}</span>
        </div>
      )}
      {errored && (
        <div style={{ position:"absolute", inset:0, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:8, background:"#0a0b0e", padding:16 }}>
          <span style={{ fontSize:28 }}>🎬</span>
          <span style={{ color:"#c9a84c", fontSize:11, fontWeight:700, letterSpacing:".15em", textTransform:"uppercase", textAlign:"center" }}>{lbl}</span>
          <a href={vid.src} target="_blank" rel="noopener noreferrer"
            style={{ color:"#6b7280", fontSize:11, textDecoration:"underline", textAlign:"center", marginTop:4 }}>
            Buka video di tab baru ↗
          </a>
        </div>
      )}
    </div>
  );
}

