                  <span style={{fontSize:10,fontWeight:700,color:"#c9a84c",border:"1px solid rgba(201,168,76,.35)",borderRadius:100,padding:"2px 9px",whiteSpace:"nowrap",flexShrink:0}}>{dur}</span>
